from abc import ABC, abstractmethod

class NotificationGateway(ABC):
    @abstractmethod
    def send(self, recipient: str, body: str) -> None: ...
# small port; no SendGrid or Twilio types appear here

from notify.gateway import NotificationGateway
from sendgrid import SendGridAPIClient   # the ONLY file in the repo that imports sendgrid

class EmailNotifier(NotificationGateway):
    def __init__(self, client: SendGridAPIClient):
        self._client = client
    def send(self, recipient, body):
        self._client.send(to=recipient, body=body)

class NotificationService:
    def __init__(self, gateway: NotificationGateway):   # depends on the port only
        self._gateway = gateway
    def notify(self, recipient: str, body: str) -> None:
        self._gateway.send(recipient, body)
# service.py never imports sendgrid or any vendor SDK
